const express = require('express');
const mongoose = require('mongoose');

const app = express();
app.use(express.json());

const queryBuilder = async (Model, filter = {}, projection = {}, sort = {}) => {
    try {
        const results = await Model.find(filter, projection).sort(sort).exec();
        return results;
    } catch (error) {
        throw new Error('Database query failed');
    }
};

// Example Mongoose model
const User = mongoose.model('User', new mongoose.Schema({
    name: String,
    age: Number,
    password: String,
    createdAt: { type: Date, default: Date.now }
}));

app.post('/api/users/query', async (req, res) => {
    const { filter, projection, sort } = req.body;

    // Security: Validate input to prevent injection attacks
    const sanitizedFilter = JSON.parse(JSON.stringify(filter));
    const sanitizedProjection = JSON.parse(JSON.stringify(projection));
    const sanitizedSort = JSON.parse(JSON.stringify(sort));

    try {
        const users = await queryBuilder(User, sanitizedFilter, sanitizedProjection, sanitizedSort);
        res.json(users);
    } catch (error) {
        res.status(500).json({ message: error.message });
    }
});

// Connect to MongoDB and start the server
mongoose.connect('mongodb://localhost:27017/admin-dashboard', { useNewUrlParser: true, useUnifiedTopology: true })
    .then(() => {
        app.listen(3000, () => {
            console.log('Server is running on port 3000');
        });
    })
    .catch(err => console.error('MongoDB connection error:', err));